Greedy insertion with capacity-aware best-fit selection per order, trying all existing non-empty assigns first in randomized order, then considering empty slots, falling back to seed insertion if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	nonEmptyIdx := make([]int, 0, MAXASSIGNS)
	emptyIdx := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			nonEmptyIdx = append(nonEmptyIdx, i)
		} else {
			emptyIdx = append(emptyIdx, i)
		}
	}
	rand.Shuffle(len(nonEmptyIdx), func(i, j int) {
		nonEmptyIdx[i], nonEmptyIdx[j] = nonEmptyIdx[j], nonEmptyIdx[i]
	})
	rand.Shuffle(len(emptyIdx), func(i, j int) {
		emptyIdx[i], emptyIdx[j] = emptyIdx[j], emptyIdx[i]
	})
	allCandidates := append(nonEmptyIdx, emptyIdx...)
	nextNewIdx := dispatch.AssignsLen
	for _, oi := range orderIndices {
		inserted := false
		bestIdx := -1
		bestCostDelta := math.MaxFloat64
		for _, ai := range allCandidates {
			idx := ai
			if idx >= nextNewIdx && idx < MAXASSIGNS {
				continue
			}
			oldCost := dispatch.Assigns[idx].Cost
			success := dispatch.Assigns[idx].AddShip(total_ship+oi, oris[oi], dess[oi])
			if success {
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				if newCost >= 0 {
					costDelta := newCost - oldCost
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestIdx = idx
					}
				}
				dispatch.Assigns[idx].RemoveShip(total_ship + oi)
				dispatch.Assigns[idx].GenRoute()
			}
		}
		if bestIdx != -1 {
			ok := dispatch.Assigns[bestIdx].AddShip(total_ship+oi, oris[oi], dess[oi])
			if ok {
				dispatch.Assigns[bestIdx].GenRoute()
				if bestIdx == nextNewIdx && nextNewIdx < MAXASSIGNS {
					nextNewIdx++
					dispatch.AssignsLen = nextNewIdx
				}
				inserted = true
			}
		}
		if !inserted {
			if nextNewIdx < MAXASSIGNS {
				ok := dispatch.Assigns[nextNewIdx].AddShip(total_ship+oi, oris[oi], dess[oi])
				if ok {
					dispatch.Assigns[nextNewIdx].GenRoute()
					dispatch.AssignsLen++
					nextNewIdx++
				}
			} else {
				fallbackOk := false
				for fi := 0; fi < MAXASSIGNS; fi++ {
					ok := dispatch.Assigns[fi].AddShip(total_ship+oi, oris[oi], dess[oi])
					if ok {
						dispatch.Assigns[fi].GenRoute()
						fallbackOk = true
						break
					}
				}
				if !fallbackOk {
					for fj := 0; fj < MAXASSIGNS; fj++ {
						dispatch.Assigns[fj].RemoveShip(total_ship + oi)
						dispatch.Assigns[fj].GenRoute()
					}
				}
			}
		}
		if nextNewIdx > dispatch.AssignsLen {
			dispatch.AssignsLen = nextNewIdx
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

