func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		insertOk  bool
	}
	for shipIdx := range oris {
		bestCandidate := candidate{-1, 1e100, false}
		safeSeedCandidate := candidate{-1, 1e100, false}
		orderId := total_ship + shipIdx
		for i := 0; i < MAXASSIGNS; i++ {
			if i >= dispatch.AssignsLen {
				continue
			}
			oldCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(orderId, oris[shipIdx], dess[shipIdx])
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				delta := newCost - oldCost
				if delta >= 0 && delta < bestCandidate.costDelta {
					bestCandidate.assignIdx = i
					bestCandidate.costDelta = delta
					bestCandidate.insertOk = true
				}
				dispatch.Assigns[i].RemoveShip(orderId)
				dispatch.Assigns[i].GenRoute()
			} else {
				dispatch.Assigns[i].Cost = oldCost
			}
		}
		if !bestCandidate.insertOk {
			for i := 0; i <= dispatch.AssignsLen && i < MAXASSIGNS; i++ {
				if i == dispatch.AssignsLen {
					if i >= MAXASSIGNS {
						break
					}
				}
				ok := dispatch.Assigns[i].AddShip(orderId, oris[shipIdx], dess[shipIdx])
				if ok {
					dispatch.Assigns[i].GenRoute()
					newCost := dispatch.Assigns[i].Cost
