			}
		}
		if bestCandidate.insertOk {
			finalIdx := bestCandidate.assignIdx
			if finalIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
			dispatch.Assigns[finalIdx].AddShip(orderId, oris[shipIdx], dess[shipIdx])
			dispatch.Assigns[finalIdx].GenRoute()
		} else {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(orderId, oris[shipIdx], dess[shipIdx])
				dispatch.Assigns[fallbackIdx].GenRoute()
				if dispatch.Assigns[fallbackIdx].Cost >= 0 {
