New algorithm: greedy best-fit insertion with fallback to empty route creation when needed, evaluating insertion cost increase via marginal distance and time window feasibility, processing orders sequentially without early termination.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    orderCount := len(oris)
    if orderCount != len(dess) || orderCount == 0 {
        dispatch.RenewnTotalCost()
        return dispatch
    }

    nextShipID := total_ship

    for oi := 0; oi < orderCount; oi++ {
        bestAssignIdx := -1
        bestCostIncrease := math.MaxFloat64
        tempAssigns := make([]Assign, dispatch.AssignsLen+orderCount)

        for ai := 0; ai < dispatch.AssignsLen+orderCount; ai++ {
            idx := ai
            if ai < dispatch.AssignsLen {
                tempAssigns[idx] = dispatch.Assigns[ai]
            } else {
                tempAssigns[idx] = Assign{}
            }
            if tempAssigns[idx].AddShip(nextShipID+oi, oris[oi], dess[oi]) {
                tempAssigns[idx].GenRoute()
                if tempAssigns[idx].Cost >= 0 {
                    var originalCost float64
                    if ai < dispatch.AssignsLen {
                        originalCost = dispatch.Assigns[ai].Cost
                    } else {
                        originalCost = 0.0
                    }
                    costIncrease := tempAssigns[idx].Cost - originalCost
                    if costIncrease < bestCostIncrease {
                        bestCostIncrease = costIncrease
                        bestAssignIdx = ai
                    }
                }
            }
            if ai < dispatch.AssignsLen {
                tempAssigns[idx].RemoveShip(nextShipID + oi)
                tempAssigns[idx].GenRoute()
            }
