func assignSnapshot(a Assign) Assign { return a }
func slackOf(asg Assign, ori, des Station) float64 {
	s := 0.0
	arr1 := cal_dis(asg.StationCurrent, ori)
	dead1 := arr1 + float64(ori.TimeStart)
	wait1 := float64(ori.TimeStart) - dead1
	if wait1 > 0 {
		s += wait1
	}
	leg2 := cal_dis(ori, des)
	etaDes := dead1 + leg2
	wait2 := float64(des.TimeStart) - etaDes
	if wait2 > 0 {
		s += wait2
	}
	return s
}
func normalize(v float64) float64 {
	if v < 0 { return 0 }
	const scale = 10000.0
	return v / scale
}
func normalizeSlack(v float64) float64 {
	const scale = 5000.0
	val := v / scale
	if val > 1 { return 1 }
	if val < 0 { return 0 }
	return val

