func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type assignIndex struct {
		idx  int
		cost float64
	}
	orderIndices := make([]int, len(oris))
	for i := range oris {
		orderIndices[i] = i
	}
	for _, jj := range orderIndices {
		inserted := false
		priorityList := make([]assignIndex, 0, dispatch.AssignsLen+1)
		for idx := 0; idx < dispatch.AssignsLen; idx++ {
			priorityList = append(priorityList, assignIndex{idx: idx, cost: dispatch.Assigns[idx].Cost})
		}
		for idx := dispatch.AssignsLen; idx < MAXASSIGNS; idx++ {
			if dispatch.Assigns[idx].StationsLen == 0 {
				priorityList = append(priorityList, assignIndex{idx: idx, cost: 0})
				break
			}
		}
		sort.SliceStable(priorityList, func(i, j int) bool {
			return priorityList[i].cost < priorityList[j].cost
		})
		for _, ai := range priorityList {
			oldCost := dispatch.Assigns[ai.idx].Cost
			if dispatch.Assigns[ai.idx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ai.idx].GenRoute()
				if dispatch.Assigns[ai.idx].Cost >= 0 {
					if ai.idx >= dispatch.AssignsLen {
						dispatch.AssignsLen = ai.idx + 1
					}
					inserted = true
					break
				}
			}
			dispatch.Assigns[ai.idx].RemoveShip(total_ship + jj)
			dispatch.Assigns[ai.idx].GenRoute()
			if dispatch.Assigns[ai.idx].Cost < 0 && oldCost >= 0 {
				dispatch.Assigns[ai.idx].Cost = oldCost
			}
		}
		if !inserted {
			for idx := 0; idx < MAXASSIGNS; idx++ {
				if dispatch.Assigns[idx].StationsLen == 0 {
					if dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
						dispatch.Assigns[idx].GenRoute()
						if dispatch.Assigns[idx].Cost >= 0 {
							if idx >= dispatch.AssignsLen {
