Modified algorithm that evaluates all feasible insertions across vehicles, selects the best based on marginal cost increase, falls back to creating a new vehicle if no feasible insertion exists, then renews total cost.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nextID := total_ship
	for oIdx := range oris {
		ori := oris[oIdx]
		des := dess[oIdx]
		bestAssignIdx := -1
		bestDelta := math.Inf(1)
		bestOriginalCost := 0.0

		for i := 0; i <= dispatch.AssignsLen && i < MAXASSIGNS; i++ {
			isNewVehicle := i == dispatch.AssignsLen
			if isNewVehicle {
				if dispatch.AssignsLen >= MAXASSIGNS {
					continue
				}
				dispatch.Assigns[i] = Assign{}
			}

			assign := &dispatch.Assigns[i]
			originalCost := assign.Cost
			if assign.AddShip(nextID, ori, des) {
				assign.GenRoute()
				newCost := assign.Cost
				delta := newCost - originalCost
				if delta >= 0 && delta < bestDelta {
					bestDelta = delta
					bestAssignIdx = i
					bestOriginalCost = originalCost
				} else if newCost < 0 {
					delta = math.Inf(1)
				}
				assign.RemoveShip(nextID)
				assign.GenRoute()
			}
		}

		if bestAssignIdx != -1 {
			chosen := &dispatch.Assigns[bestAssignIdx]
			chosen.AddShip(nextID, ori, des)
			chosen.GenRoute()
			if bestAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(nextID, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				dispatch.AssignsLen++
			}
		}
		nextID++
	}
	dispatch.RenewnTotalCost()
	return dispatch

